		if(dict.find(key) != dict.end()){
			dict[key].first = value;
			dict[key].second = timestamp;
		}else
			dict[key] = make_pair(value, timestamp);
	}

	int get(int key) {
		if(dict.find(key) == dict.end())
			return -1;

		int v = dict[key].first;
		int t = dict[key].second;
		if(t < lastSet)
			return setVal;
		else
			return v;
	}

	void setAll(int value) {
		++timestamp;
		setVal = value;
		lastSet = timestamp;
		++timestamp;
	}
