class CustomMap {
    private val map = mutableMapOf<Int, Pair<Int, Long>>()
    private var version = 0L
    private var allVal: Int? = null

    operator fun set(key: Int, value: Int) {
        map[key] = value to version
    }

    operator fun get(key: Int): Int? {
        val (value, valVersion) = map[key] ?: return null
        return if (valVersion < version) allVal else value
    }

    fun setAll(value: Int) {
        version++
        allVal = value
    }
}

fun main() {
    val map = CustomMap()
    map[0] = 1
    map[0].let(::println) // 1
    map[1] = 2
    map[1].let(::println) // 2
    map.setAll(5)
    map[0].let(::println) // 5
    map[1].let(::println) // 5
    map[2].let(::println) // null, there's no such key
    map[2] = 7
    map[0].let(::println) // 5
    map[1].let(::println) // 5
    map[2].let(::println) // 7
}
